import React, { useState } from 'react';
import '../styles/Katalog.css';

const Katalog = ({ kataKunci }) => {
  const [kategoriAktif, setKategoriAktif] = useState('Semua Produk');

  // Menambahkan properti "tags" berisi kata kunci terjemahan atau sinonim
  const [produk] = useState([
    { id: 1, nama: 'Black Forest Cake', harga: 'Rp 150.000', kategori: 'Kue Ulang Tahun', img: 'https://images.unsplash.com/photo-1606890737304-57a1ca8a5b62?auto=format&fit=crop&q=80', tags: ['hitam', 'hutan', 'cokelat', 'ceri'] },
    { id: 2, nama: 'Cheesecake', harga: 'Rp 85.000', kategori: 'Kue Ulang Tahun', img: 'https://images.unsplash.com/photo-1533134242443-d4fd215305ad?auto=format&fit=crop&q=80', tags: ['keju', 'kue keju'] },
    { id: 3, nama: 'Tiramisu Dessert Box', harga: 'Rp 45.000', kategori: 'Dessert Box', img: 'https://images.unsplash.com/photo-1571115177098-24edf3e00b65?auto=format&fit=crop&q=80', tags: ['kopi', 'cokelat bubuk'] },
    { id: 4, nama: 'Nastar Keju Premium', harga: 'Rp 120.000', kategori: 'Kue Kering', img: 'https://images.unsplash.com/photo-1605335967732-2b6389fccb8c?auto=format&fit=crop&q=80', tags: ['nanas', 'kue lebaran'] },
    { id: 5, nama: 'Red Velvet Cake', harga: 'Rp 140.000', kategori: 'Kue Ulang Tahun', img: 'https://images.unsplash.com/photo-1616541823729-00fe0aacd32c?auto=format&fit=crop&q=80', tags: ['merah', 'beludru'] },
    { id: 6, nama: 'Bolu Cukke\'', harga: 'Rp 60.000', kategori: 'Kue Kering', img: 'https://images.unsplash.com/photo-1587241321921-91a834d6d191?auto=format&fit=crop&q=80', tags: ['tradisional', 'gula merah'] }
  ]);

  const daftarKategori = ['Semua Produk', 'Kue Ulang Tahun', 'Dessert Box', 'Kue Kering'];

  const produkDifilter = produk.filter(kue => {
    // Mengecek kesesuaian kategori di sidebar
    const cocokKategori = kategoriAktif === 'Semua Produk' || kue.kategori === kategoriAktif;
    
    // Menyiapkan teks pencarian menjadi huruf kecil semua
    const kataPencarian = kataKunci ? kataKunci.toLowerCase() : '';
    
    // Mengecek apakah kata pencarian ada di nama resmi produk
    const cocokNama = kue.nama.toLowerCase().includes(kataPencarian);
    
    // Mengecek apakah kata pencarian ada di dalam array tags tersembunyi
    const cocokTags = kue.tags.some(tag => tag.toLowerCase().includes(kataPencarian));
    
    // Produk lolos filter jika namanya cocok ATAU tags-nya cocok, DAN kategorinya sesuai
    const cocokPencarian = cocokNama || cocokTags;
    
    return cocokKategori && cocokPencarian;
  });

  return (
    <div className="katalog-wrapper">
      <div className="katalog-overlay"></div>
      
      <div className="katalog-content">
        <aside className="sidebar">
          <h3>Kategori</h3>
          {daftarKategori.map(kategori => (
            <div 
              key={kategori}
              className={`category-item ${kategoriAktif === kategori ? 'active' : ''}`}
              onClick={() => setKategoriAktif(kategori)}
            >
              {kategori}
            </div>
          ))}
        </aside>

        <div className="product-grid">
          {produkDifilter.map((kue) => (
            <div key={kue.id} className="product-card">
              <img src={kue.img} alt={kue.nama} className="product-image" />
              <div className="product-info">
                <p className="product-name">{kue.nama}</p>
                <p className="product-price">{kue.harga}</p>
                <button className="btn-add">+ Masukkan Keranjang</button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Katalog;
